import 'package:http/http.dart' as http;

class ApiService {
  static const String cloudApiUrl = "https://api.example.com";
  static const String localDeviceUrl = "http://192.168.x.x";

  Future<http.Response> getCloudData(String apiKey) async {
    final response = await http.get(Uri.parse('$cloudApiUrl?api_key=$apiKey'));

    if (response.statusCode != 200) {
      throw Exception('Failed to load cloud data');
    }

    return response;
  }

  Future<http.Response> getLocalDeviceData() async {
    final response = await http.get(Uri.parse(localDeviceUrl));

    if (response.statusCode != 200 && response.statusCode != 204) {
      throw Exception('Failed to load local device data');
    }

    return response;
  }
}